        $('#mainBtn').click(function () {
            timeBoolean = true;
            $("#myModal").hide();
            closePage();
        });
        $('#svgBtn').click(function () {
            timeBoolean = true;
            $("#myModal").hide();
            closePage();
        });

        $('#svgBtn2').click(function () {
            timeBoolean2 = true;
            $("#myModal2").hide();
            closePage();
        });

        function closePage() {
            if (typeof WeixinJSBridge == "object" && typeof WeixinJSBridge.invoke == "function") {
                WeixinJSBridge.call('closeWindow');
            }
        }
        // 结束任务
        function overTask(finishNum, taskText, text) {
            $("#finishNum").text(finishNum);
            $("#taskText").text(taskText);
            titleText2.text(text);
            $("#myModal2").show();
            timerTask2();
        }
        //获取url中的参数
        function getParamValue(name) {
            var reg = new RegExp("(^|&)" + name + "=([^&]*)(&|$)");
            var r = window.location.search.substr(1).match(reg);
            if (r != null) return unescape(r[2]);
            return null;
        }

        /**倒计时-开始任务*/
        function timerTask() {
            var countdownDuration = 8; // 倒计时时间（秒）
            var timer = setInterval(function () {
                var seconds = parseInt(countdownDuration % 90, 10);
                seconds = seconds < 8 ? seconds : seconds;
                display.text(countdownDuration);
                if (--countdownDuration < 0) {
                    clearInterval(timer);
                    $("#finishNum").text("获取中");
                    if (timeBoolean == false) {
                        $("#myModal").hide();
                        closePage();
                    }
                }
            }, 1000);
        }

        /**倒计时-关闭页面*/
        function timerTask2() {
            var countdownDuration = 3;
            var timer = setInterval(function () {
                var seconds = parseInt(countdownDuration % 60, 10);
                seconds = seconds < 3 ? seconds : seconds;
                display2.text(seconds);
                if (--countdownDuration < 0) {
                    clearInterval(timer);
                    $("#finishNum").text("获取中");
                    if (timeBoolean2 == false) {
                        $("#myModal2").hide();
                        closePage();
                    }
                }
            }, 1000);
        }


